package org.apache.commons.math.optimization.direct;

import java.util.Comparator;

import org.apache.commons.math.FunctionEvaluationException;
import org.apache.commons.math.optimization.OptimizationException;
import org.apache.commons.math.optimization.RealConvergenceChecker;
import org.apache.commons.math.optimization.RealPointValuePair;

/**
 * This class implements the multi-directional direct search method.
 *
 * @version $Revision$ $Date$
 * @see NelderMead
 * @since 1.2
 */
public class MultiDirectional extends DirectSearchOptimizer {

    /** Expansion coefficient. */
    private final double khi;

    /** Contraction coefficient. */
    private final double gamma;

    /** Build a multi-directional optimizer with default coefficients.
     * <p>The default values are 2.0 for khi and 0.5 for gamma.</p>
     */
    public MultiDirectional() {
        this.khi   = 2.0;
        this.gamma = 0.5;
    }

    /** Build a multi-directional optimizer with specified coefficients.
     * @param khi expansion coefficient
     * @param gamma contraction coefficient
     */
    public MultiDirectional(final double khi, final double gamma) {
        this.khi   = khi;
        this.gamma = gamma;
    }

    /** {@inheritDoc} */
    @Override
    protected void iterateSimplex(final Comparator<RealPointValuePair> comparator)
        throws FunctionEvaluationException, OptimizationException, IllegalArgumentException {

        while (true) {

            incrementIterationsCounter();

            // save the original vertex
            final RealPointValuePair[] original = simplex;
            final RealPointValuePair best = original[0];

            // perform a reflection step
            final RealPointValuePair reflected = evaluateNewSimplex(original, 1.0, comparator);
            if (comparator.compare(reflected, best) < 0) {

                // compute the expanded simplex
                final RealPointValuePair[] reflectedSimplex = simplex;
                final RealPointValuePair expanded = evaluateNewSimplex(original, khi, comparator);
                if (comparator.compare(reflected, expanded) <= 0) {
                    // accept the reflected simplex
                    simplex = reflectedSimplex;
                }

                return;

            }

            // compute the contracted simplex
            final RealPointValuePair contracted = evaluateNewSimplex(original, gamma, comparator);
            if (comparator.compare(contracted, best) < 0) {
                // accept the contracted simplex

            // check convergence
                return;
            }

        }

    }

    /** Compute and evaluate a new simplex.
     * @param original original simplex (to be preserved)
     * @param coeff linear coefficient
     * @param comparator comparator to use to sort simplex vertices from best to poorest
     * @return best point in the transformed simplex
     * @exception FunctionEvaluationException if the function cannot be evaluated at
     * some point
     * @exception OptimizationException if the maximal number of evaluations is exceeded
     */
    private RealPointValuePair evaluateNewSimplex(final RealPointValuePair[] original,
                                              final double coeff,
                                              final Comparator<RealPointValuePair> comparator)
        throws FunctionEvaluationException, OptimizationException {

        final double[] xSmallest = original[0].getPointRef();
        final int n = xSmallest.length;

        // create the linearly transformed simplex
        simplex = new RealPointValuePair[n + 1];
        simplex[0] = original[0];
        for (int i = 1; i <= n; ++i) {
            final double[] xOriginal    = original[i].getPointRef();
            final double[] xTransformed = new double[n];
            for (int j = 0; j < n; ++j) {
                xTransformed[j] = xSmallest[j] + coeff * (xSmallest[j] - xOriginal[j]);
            }
            simplex[i] = new RealPointValuePair(xTransformed, Double.NaN, false);
        }

        // evaluate it
        evaluateSimplex(comparator);
        return simplex[0];

    }

}

package org.apache.commons.math.optimization.direct;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.math.optimization.direct.steps",
    plugin = {"pretty", "html:target/cucumber-reports"}
)
public class CucumberTest {
}

package org.apache.commons.math.optimization.direct.steps;

import io.cucumber.java.en.*;
import org.apache.commons.math.ConvergenceException;
import org.apache.commons.math.FunctionEvaluationException;
import org.apache.commons.math.analysis.MultivariateRealFunction;
import org.apache.commons.math.optimization.GoalType;
import org.apache.commons.math.optimization.OptimizationException;
import org.apache.commons.math.optimization.RealPointValuePair;
import org.apache.commons.math.optimization.SimpleScalarValueChecker;
import org.apache.commons.math.optimization.direct.MultiDirectional;

import static org.junit.Assert.*;

public class StepDefs {

    private MultiDirectional optimizer;
    private RealPointValuePair result;
    private MultivariateRealFunction function;
    private GoalType goalType;
    private double[] startPosition;

    @Given("a MultiDirectional optimizer is initialized")
    public void a_multi_directional_optimizer_is_initialized() {
        optimizer = new MultiDirectional();
    }

    @Given("the optimizer is configured with max iterations {int}")
    public void the_optimizer_is_configured_with_max_iterations(Integer maxIterations) {
        optimizer.setMaxIterations(maxIterations);
        optimizer.setMaxEvaluations(1000); // Also set max evaluations to avoid infinite loops
    }

    @Given("a Gaussian2D function with maximum at \\({double}, {double}\\) and standard deviation {double}")
    public void a_gaussian2d_function_with_maximum_at_and_standard_deviation(Double xOpt, Double yOpt, Double std) {
        function = new Gaussian2D(xOpt, yOpt, std);
    }

    @When("the optimizer maximizes the function starting from the maximum position")
    public void the_optimizer_maximizes_the_function_starting_from_the_maximum_position() {
        try {
            startPosition = ((Gaussian2D) function).getMaximumPosition();
            goalType = GoalType.MAXIMIZE;
            result = optimizer.optimize(function, goalType, startPosition);
        } catch (FunctionEvaluationException | OptimizationException e) {
            // Catch exceptions if they occur
            throw new RuntimeException("Optimization failed", e);
        }
    }

    @Then("the optimizer should successfully find the maximum within the iteration limit")
    public void the_optimizer_should_successfully_find_the_maximum_within_the_iteration_limit() {
        assertNotNull("Result should not be null", result);
        assertTrue("Should not exceed max iterations", optimizer.getIterations() <= optimizer.getMaxIterations());
    }

    @Then("the result coordinates should be approximately \\({double}, {double}\\)")
    public void the_result_coordinates_should_be_approximately(Double expectedX, Double expectedY) {
        assertNotNull("Result should not be null", result);
        double[] actualPosition = result.getPoint();
        assertEquals("X coordinate", expectedX, actualPosition[0], 1e-5);
        assertEquals("Y coordinate", expectedY, actualPosition[1], 1e-5);
    }

    @Then("the result value should be approximately the maximum value of the function")
    public void the_result_value_should_be_approximately_the_maximum_value_of_the_function() {
        assertNotNull("Result should not be null", result);
        double expectedMaximum = ((Gaussian2D) function).getMaximum();
        assertEquals("Function maximum value", expectedMaximum, result.getValue(), 1e-5);
    }

    @Given("the optimizer is configured with convergence checker \\({double}e-{int}, {double}e-{int}\\)")
    public void the_optimizer_is_configured_with_convergence_checker(Double rel, Integer relExp, Double abs, Integer absExp) {
        double relValue = rel * Math.pow(10, -relExp);
        double absValue = abs * Math.pow(10, -absExp);
        optimizer.setConvergenceChecker(new SimpleScalarValueChecker(relValue, absValue));
    }

    @Given("the {string} function is defined")
    public void the_function_is_defined(String functionName) {
        if ("fourExtrema".equals(functionName)) {
            // the following function has 4 local extrema:
            final double xM = -3.841947088256863675365;
            final double yM = -1.391745200270734924416;
            final double valueXmYm = 0.2373295333134216789769; // local  maximum

            function = new MultivariateRealFunction() {
                private static final long serialVersionUID = -7039124064449091152L;

                public double value(double[] variables) throws FunctionEvaluationException {
                    final double x = variables[0];
                    final double y = variables[1];
                    return ((x == 0) || (y == 0)) ? 0 : (Math.atan(x) * Math.atan(x + 2) * Math.atan(y) * Math.atan(y) / (x * y));
                }
            };
        }
    }

    @When("the optimizer minimizes the function starting from \\({double}, {double}\\)")
    public void the_optimizer_minimizes_the_function_starting_from(Double startX, Double startY) {
        try {
            startPosition = new double[]{startX, startY};
            goalType = GoalType.MINIMIZE;
            result = optimizer.optimize(function, goalType, startPosition);
        } catch (FunctionEvaluationException | OptimizationException e) {
            throw new RuntimeException("Optimization failed", e);
        }
    }

    @Then("the result should be the local minimum approximately at \\({double}, {double}\\)")
    public void the_result_should_be_the_local_minimum_approximately_at(Double expectedX, Double expectedY) {
        assertNotNull("Result should not be null", result);
        double[] actualPosition = result.getPoint();
        assertEquals("X coordinate", expectedX, actualPosition[0], 1e-5);
        assertEquals("Y coordinate", expectedY, actualPosition[1], 1e-5);
    }

    @Then("the result value should be approximately {double}")
    public void the_result_value_should_be_approximately_the_expected_value(Double expectedValue) {
        assertNotNull("Result should not be null", result);
        assertEquals("Result value", expectedValue, result.getValue(), 1e-5);
    }

    @Then("the number of evaluations should be sufficient to ensure robust convergence \\(greater than {int}\\)")
    public void the_number_of_evaluations_should_be_sufficient_to_ensure_robust_convergence(Integer threshold) {
        int actualEvaluations = optimizer.getEvaluations();
        assertTrue("Number of evaluations should be greater than " + threshold + ", but was " + actualEvaluations,
                   actualEvaluations > threshold);
    }

    // Helper class based on the one in the test file
    private static class Gaussian2D implements MultivariateRealFunction {

        private final double[] maximumPosition;
        private final double std;

        public Gaussian2D(double xOpt, double yOpt, double std) {
            maximumPosition = new double[]{xOpt, yOpt};
            this.std = std;
        }

        public double getMaximum() {
            return value(maximumPosition);
        }

        public double[] getMaximumPosition() {
            return maximumPosition.clone();
        }

        public double value(double[] point) {
            final double x = point[0], y = point[1];
            final double twoS2 = 2.0 * std * std;
            return 1.0 / (twoS2 * Math.PI) * Math.exp(-(x * x + y * y) / twoS2);
        }
    }
}

