protected void iterateSimplex(final Comparator<RealPointValuePair> comparator)
    throws FunctionEvaluationException, OptimizationException, IllegalArgumentException {

    incrementIterationsCounter();

    // save the original vertex (before any transformations)
    final RealPointValuePair[] original = simplex.clone();
    final RealPointValuePair bestOriginal = original[0];

    // perform a reflection step
    final RealPointValuePair reflected = evaluateNewSimplex(original, 1.0, comparator);
    final RealPointValuePair[] reflectedSimplex = simplex; // Save the reflected simplex

    // Check if reflection is better than original best
    if (comparator.compare(reflected, bestOriginal) < 0) {
        // compute the expanded simplex to see if we can do even better
        final RealPointValuePair expanded = evaluateNewSimplex(original, khi, comparator);

        // If reflection is better than or equal to expansion, use the reflection simplex
        if (comparator.compare(reflected, expanded) <= 0) {
            // reflectedSimplex is already in 'simplex' from the evaluateNewSimplex call
            return;
        } else {
            // Expansion is better, so the expanded simplex is already in 'simplex'
            return;
        }
    }

    // Reflection didn't improve, so try contraction
    // Restore original simplex first
    simplex = original;

    // compute the contracted simplex
    final RealPointValuePair contracted = evaluateNewSimplex(original, gamma, comparator);

    // If contraction is better than the original best, accept it
    if (comparator.compare(contracted, bestOriginal) < 0) {
        // contracted simplex is already in 'simplex' from evaluateNewSimplex call
        return;
    }

    // If both reflection and contraction didn't help, shrink the simplex around the best point
    final double[] xBest = bestOriginal.getPointRef();
    final int n = xBest.length;

